const trig = $('Start').first().json || {};
const skuInput = (trig.sku || '').toString().trim();
const mes = (trig.mes || '').toString().trim();

if (!skuInput) {
  return [{ json: { erro: 'Informe o SKU (código exato ou trecho da descrição).', exemplo: { sku: '76155035', mes: '2026-07' } } }];
}

const raw = $json.response;
let env = null;
try {
  if (Array.isArray(raw)) env = JSON.parse(raw[0]);
  else if (typeof raw === 'string') env = JSON.parse(raw);
} catch (e) {
  env = null;
}

if (!env || !Array.isArray(env.data) || !env.data.length) {
  return [{ json: { erro: 'Sem previsão em cache. Rode a previsão (Predict) antes de pedir explicação.' } }];
}

const data = env.data;
const q = skuInput.toLowerCase();
const isExact = (r) => String(r.SKU || '').toLowerCase() === q;
const isText = (r) => String(r.SKU || '').toLowerCase().includes(q) || String(r['Descrição'] || '').toLowerCase().includes(q);

const exact = data.filter(isExact);
const hits = exact.length ? exact : data.filter(isText);

if (!hits.length) {
  return [{ json: { erro: `Nenhum SKU encontrado para '${skuInput}'.` } }];
}

if (hits.length > 1) {
  return [{
    json: {
      erro: `Encontrei ${hits.length} SKUs para '${skuInput}'. Seja mais específico no código.`,
      opcoes: hits.slice(0, 10).map((r) => ({ sku: r.SKU, descricao: r['Descrição'] }))
    }
  }];
}

const row = hits[0];
const detalhes = row.detalhes || {};
let meses = Object.keys(detalhes).sort();
if (mes) meses = meses.filter((m) => m === mes);

if (!meses.length) {
  return [{ json: { erro: mes ? `O SKU ${row.SKU} não tem dados para o mês ${mes}.` : `O SKU ${row.SKU} não possui detalhes de previsão.` } }];
}

function n(v, d = 2) {
  if (v == null || Number.isNaN(Number(v))) return null;
  return Number(Number(v).toFixed(d));
}

function dominantMethod(metodos, pesos) {
  if (!pesos || typeof pesos !== 'object') return null;
  let best = null;
  for (const k of Object.keys(pesos)) {
    const w = Number(pesos[k]);
    if (!Number.isFinite(w)) continue;
    if (!best || w > best.peso) best = { metodo: k, peso: w, valor: metodos && metodos[k] != null ? Number(metodos[k]) : null };
  }
  return best;
}

function labelMetodo(k) {
  const map = {
    heuristica: 'Heurística de tendência',
    suavizacaoExponencial: 'Suavização exponencial',
    tendenciaSazonal: 'Tendência sazonal',
    mediaMovel3: 'Média móvel de 3 meses'
  };
  return map[k] || k;
}

function explainMonth(m, d) {
  const ic = d.intervaloConfianca || {};
  const met = d.metodos || null;
  const pes = d.pesos || null;
  const dmp = d.damping || {};
  const dom = dominantMethod(met, pes);

  const previsaoFinal = d.previsao != null ? Number(d.previsao) : null;
  const faixaMin = ic.lower != null ? Number(ic.lower) : null;
  const faixaMax = ic.upper != null ? Number(ic.upper) : null;

  let baseEnsemble = null;
  if (met && pes) {
    const hs = Number(met.heuristica || 0) * Number(pes.heuristica || 0);
    const sx = Number(met.suavizacaoExponencial || 0) * Number(pes.suavizacaoExponencial || 0);
    const ts = Number(met.tendenciaSazonal || 0) * Number(pes.tendenciaSazonal || 0);
    const mm3 = Number(met.mediaMovel3 || 0) * Number(pes.mediaMovel3 || 0);
    const b = hs + sx + ts + mm3;
    if (Number.isFinite(b)) baseEnsemble = b;
  }

  const narrativa = [];
  narrativa.push(`No mês ${m}, a previsão final do SKU ${row.SKU} ficou em ${previsaoFinal != null ? Math.round(previsaoFinal) : 'n/d'} peças, com faixa de ${faixaMin != null ? Math.round(faixaMin) : 'n/d'} a ${faixaMax != null ? Math.round(faixaMax) : 'n/d'}.`);

  if (dom) {
    narrativa.push(`O método com maior peso foi ${labelMetodo(dom.metodo)} (${n(dom.peso * 100, 1)}%), puxando a base para ${dom.valor != null ? Math.round(dom.valor) : 'n/d'} peças.`);
  }

  if (baseEnsemble != null) {
    narrativa.push(`Antes dos ajustes de segurança, a base combinada estava em ${Math.round(baseEnsemble)} peças.`);
  }

  if (dmp && Object.keys(dmp).length) {
    if (dmp.selector) narrativa.push(`A decisão aplicada foi '${dmp.selector}'.`);
    if (dmp.regimeShift && dmp.regimeShift.direction) {
      narrativa.push(`Houve ajuste de regime (${dmp.regimeShift.direction}) para aproximar a previsão do novo patamar recente.`);
    }
    if (dmp.fenceApplied && dmp.fenceInfo) {
      narrativa.push(`Foi aplicado teto de segurança (${dmp.fenceInfo.direction}) para evitar extrapolação excessiva.`);
    }
    if (dmp.biasFactor != null && Number(dmp.biasFactor) !== 1) {
      narrativa.push(`O viés multiplicativo usado foi ${n(dmp.biasFactor, 3)}.`);
    }
    if (dmp.wRecent != null && Number(dmp.wRecent) > 0) {
      narrativa.push(`A média recente entrou com peso de ${n(Number(dmp.wRecent) * 100, 1)}% na calibração final.`);
    }
  }

  return {
    mes: m,
    resumoNegocio: narrativa.join(' '),
    numeros: {
      previsaoFinal: n(previsaoFinal, 3),
      faixaMin: n(faixaMin, 3),
      faixaMax: n(faixaMax, 3),
      tolerancePct: d.tolerancePct != null ? n(Number(d.tolerancePct), 1) : null,
      confianca: d.confianca || null,
      tipo: d.tipo || null,
      motivo: d.motivo || null,
      baseEnsemble: n(baseEnsemble, 3),
      metodoDominante: dom ? {
        metodo: dom.metodo,
        metodoLabel: labelMetodo(dom.metodo),
        pesoPct: n(dom.peso * 100, 1),
        valorMetodo: dom.valor != null ? n(dom.valor, 3) : null
      } : null
    },
    detalhesCalculo: {
      metodos: met,
      pesos: pes,
      damping: dmp
    }
  };
}

const mesesExplicados = meses.map((m) => explainMonth(m, detalhes[m] || {}));

return [{
  json: {
    sku: row.SKU,
    descricao: row['Descrição'] || '',
    formato: row.Formato || '',
    meses: mesesExplicados
  }
}];
